const __pageData = JSON.parse('{"title":"L4→L5：框架如何约束应用设计","description":"从理论层面解析框架的『不变性』与应用的『可变性』分离机制，深入探讨框架通过钩子、插槽与架构风格隐性强制对应用设计施加的结构性约束，并以 Next.js、NestJS、React 生态与 SvelteKit 为例，揭示『框架重力』在工程实践中的具体表现与反模式。","frontmatter":{"title":"L4→L5：框架如何约束应用设计","description":"从理论层面解析框架的『不变性』与应用的『可变性』分离机制，深入探讨框架通过钩子、插槽与架构风格隐性强制对应用设计施加的结构性约束，并以 Next.js、NestJS、React 生态与 SvelteKit 为例，揭示『框架重力』在工程实践中的具体表现与反模式。","date":"2026-05-01T00:00:00.000Z","tags":["framework-gravity","application-architecture","Next.js","NestJS","inversion-of-control","design-constraints","L4-L5","software-architecture","theoretical-hierarchy"],"category":"theoretical-foundations"},"headers":[],"relativePath":"theoretical-hierarchy/05-framework-to-application.md","filePath":"theoretical-hierarchy/05-framework-to-application.md","lastUpdated":1777713329000}');
